import{_ as o,c as i,o as n,a1 as t}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"opencode-notify Changelog: Version History and Feature Changes","description":"View version history and important change records for the opencode-notify plugin. Learn about feature updates, bug fixes, and configuration improvements in each version.","frontmatter":{"title":"opencode-notify Changelog: Version History and Feature Changes","sidebarTitle":"Changelog","subtitle":"Changelog","description":"View version history and important change records for the opencode-notify plugin. Learn about feature updates, bug fixes, and configuration improvements in each version.","tags":["Changelog","Version History"],"order":150},"headers":[],"relativePath":"kdcokenny/opencode-notify/changelog/release-notes/index.md","filePath":"kdcokenny/opencode-notify/changelog/release-notes/index.md"}'),a={name:"kdcokenny/opencode-notify/changelog/release-notes/index.md"};function r(l,e,s,c,d,p){return n(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><h2 id="version-notes" tabindex="-1">Version Notes <a class="header-anchor" href="#version-notes" aria-label="Permalink to &quot;Version Notes&quot;">​</a></h2><p>This plugin is distributed via OCX and does not follow traditional version numbering. Important changes are recorded below in reverse chronological order.</p><hr><h2 id="_2026-01-23" tabindex="-1">2026-01-23 <a class="header-anchor" href="#_2026-01-23" aria-label="Permalink to &quot;2026-01-23&quot;">​</a></h2><p><strong>Change Type</strong>: Sync Update</p><ul><li>Keep synchronized with kdcokenny/ocx main repository</li></ul><hr><h2 id="_2026-01-22" tabindex="-1">2026-01-22 <a class="header-anchor" href="#_2026-01-22" aria-label="Permalink to &quot;2026-01-22&quot;">​</a></h2><p><strong>Change Type</strong>: Sync Update</p><ul><li>Keep synchronized with kdcokenny/ocx main repository</li></ul><hr><h2 id="_2026-01-13" tabindex="-1">2026-01-13 <a class="header-anchor" href="#_2026-01-13" aria-label="Permalink to &quot;2026-01-13&quot;">​</a></h2><p><strong>Change Type</strong>: Sync Update</p><ul><li>Keep synchronized with kdcokenny/ocx main repository</li></ul><hr><h2 id="_2026-01-12" tabindex="-1">2026-01-12 <a class="header-anchor" href="#_2026-01-12" aria-label="Permalink to &quot;2026-01-12&quot;">​</a></h2><p><strong>Change Type</strong>: Sync Update</p><ul><li>Keep synchronized with kdcokenny/ocx main repository</li></ul><hr><h2 id="_2026-01-08" tabindex="-1">2026-01-08 <a class="header-anchor" href="#_2026-01-08" aria-label="Permalink to &quot;2026-01-08&quot;">​</a></h2><p><strong>Change Type</strong>: Sync Update</p><ul><li>Keep synchronized with kdcokenny/ocx main repository</li></ul><hr><h2 id="_2026-01-07" tabindex="-1">2026-01-07 <a class="header-anchor" href="#_2026-01-07" aria-label="Permalink to &quot;2026-01-07&quot;">​</a></h2><p><strong>Change Type</strong>: Sync Update</p><ul><li>Updated from ocx@30a9af5</li><li>Skip CI build</li></ul><hr><h2 id="_2026-01-01" tabindex="-1">2026-01-01 <a class="header-anchor" href="#_2026-01-01" aria-label="Permalink to &quot;2026-01-01&quot;">​</a></h2><h3 id="fix-cargo-style-namespace-syntax" tabindex="-1">Fix: Cargo-Style Namespace Syntax <a class="header-anchor" href="#fix-cargo-style-namespace-syntax" aria-label="Permalink to &quot;Fix: Cargo-Style Namespace Syntax&quot;">​</a></h3><p><strong>Changes</strong>:</p><ul><li>Update namespace syntax: <code>ocx add kdco-notify</code> → <code>ocx add kdco/notify</code></li><li>Update namespace syntax: <code>ocx add kdco-workspace</code> → <code>ocx add kdco/workspace</code></li><li>Rename source file: <code>kdco-notify.ts</code> → <code>notify.ts</code></li></ul><p><strong>Impact</strong>:</p><ul><li>Installation command changed from <code>ocx add kdco-notify</code> to <code>ocx add kdco/notify</code></li><li>Source code file structure is clearer, following Cargo naming conventions</li></ul><hr><h3 id="enhancement-readme-documentation" tabindex="-1">Enhancement: README Documentation <a class="header-anchor" href="#enhancement-readme-documentation" aria-label="Permalink to &quot;Enhancement: README Documentation&quot;">​</a></h3><p><strong>Changes</strong>:</p><ul><li>Improve README documentation, add value proposition explanation</li><li>Add FAQ section, answer common questions</li><li>Refine &quot;Smart Notification&quot; related descriptions</li><li>Simplify installation step instructions</li></ul><p><strong>New Content</strong>:</p><ul><li>Value proposition table (event, notification, sound, reason)</li><li>FAQ: Does it add context? Will I receive spam notifications? How to temporarily disable?</li></ul><hr><h2 id="_2025-12-31" tabindex="-1">2025-12-31 <a class="header-anchor" href="#_2025-12-31" aria-label="Permalink to &quot;2025-12-31&quot;">​</a></h2><h3 id="documentation-simplify-readme" tabindex="-1">Documentation: Simplify README <a class="header-anchor" href="#documentation-simplify-readme" aria-label="Permalink to &quot;Documentation: Simplify README&quot;">​</a></h3><p><strong>Changes</strong>:</p><ul><li>Remove invalid icons and dark mode references</li><li>Simplify README documentation, focus on core feature descriptions</li></ul><h3 id="removal-icon-support" tabindex="-1">Removal: Icon Support <a class="header-anchor" href="#removal-icon-support" aria-label="Permalink to &quot;Removal: Icon Support&quot;">​</a></h3><p><strong>Changes</strong>:</p><ul><li>Remove OpenCode icon support (cross-platform dark mode detection)</li><li>Simplify notification flow, remove unstable icon features</li><li>Clean up <code>src/plugin/assets/</code> directory</li></ul><p><strong>Removed Files</strong>:</p><ul><li><code>src/plugin/assets/opencode-icon-dark.png</code></li><li><code>src/plugin/assets/opencode-icon-light.png</code></li></ul><p><strong>Impact</strong>:</p><ul><li>Notifications no longer display custom icons</li><li>Notification flow is more stable, reduces platform compatibility issues</li></ul><h3 id="addition-opencode-icon-removed" tabindex="-1">Addition: OpenCode Icon (Removed) <a class="header-anchor" href="#addition-opencode-icon-removed" aria-label="Permalink to &quot;Addition: OpenCode Icon (Removed)&quot;">​</a></h3><p><strong>Changes</strong>:</p><ul><li>Add OpenCode icon support</li><li>Implement cross-platform dark mode detection</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>This feature was removed in later versions, see &quot;Removal: Icon Support&quot; on 2025-12-31.</p></div><h3 id="addition-terminal-detection-and-focus-awareness" tabindex="-1">Addition: Terminal Detection and Focus Awareness <a class="header-anchor" href="#addition-terminal-detection-and-focus-awareness" aria-label="Permalink to &quot;Addition: Terminal Detection and Focus Awareness&quot;">​</a></h3><p><strong>Changes</strong>:</p><ul><li>Add automatic terminal detection (supports 37+ terminals)</li><li>Add focus detection (macOS only)</li><li>Add click-to-focus (macOS only)</li></ul><p><strong>New Features</strong>:</p><ul><li>Automatically identify terminal emulators</li><li>Suppress notifications when terminal is focused</li><li>Click notification to focus terminal window (macOS)</li></ul><p><strong>Technical Details</strong>:</p><ul><li>Use <code>detect-terminal</code> library to detect terminal type</li><li>Get foreground application via macOS osascript</li><li>Use node-notifier&#39;s activate option for click-to-focus</li></ul><h3 id="addition-initial-version" tabindex="-1">Addition: Initial Version <a class="header-anchor" href="#addition-initial-version" aria-label="Permalink to &quot;Addition: Initial Version&quot;">​</a></h3><p><strong>Changes</strong>:</p><ul><li>Initial commit: kdco-notify plugin</li><li>Basic native notification functionality</li><li>Basic configuration system</li></ul><p><strong>Core Features</strong>:</p><ul><li>session.idle event notification (task completion)</li><li>session.error event notification (error)</li><li>permission.updated event notification (permission request)</li><li>node-notifier integration (cross-platform native notifications)</li></ul><p><strong>Initial Files</strong>:</p><ul><li><code>LICENSE</code> - MIT License</li><li><code>README.md</code> - Project documentation</li><li><code>registry.json</code> - OCX registration configuration</li><li><code>src/plugin/kdco-notify.ts</code> - Main plugin code</li></ul><hr><h2 id="related-resources" tabindex="-1">Related Resources <a class="header-anchor" href="#related-resources" aria-label="Permalink to &quot;Related Resources&quot;">​</a></h2><ul><li><strong>GitHub Repository</strong>: <a href="https://github.com/kdcokenny/ocx/tree/main/registry/src/kdco/notify" target="_blank" rel="noreferrer">https://github.com/kdcokenny/ocx/tree/main/registry/src/kdco/notify</a></li><li><strong>Commit History</strong>: <a href="https://github.com/kdcokenny/ocx/commits/main/registry/src/kdco/notify" target="_blank" rel="noreferrer">https://github.com/kdcokenny/ocx/commits/main/registry/src/kdco/notify</a></li><li><strong>OCX Documentation</strong>: <a href="https://github.com/kdcokenny/ocx" target="_blank" rel="noreferrer">https://github.com/kdcokenny/ocx</a></li></ul><hr><h2 id="version-policy" tabindex="-1">Version Policy <a class="header-anchor" href="#version-policy" aria-label="Permalink to &quot;Version Policy&quot;">​</a></h2><p>As part of the OCX ecosystem, this plugin adopts the following version policy:</p><ul><li><strong>No Version Numbers</strong>: Track changes via Git commit history</li><li><strong>Continuous Delivery</strong>: Sync updates with OCX main repository</li><li><strong>Backward Compatibility</strong>: Maintain backward compatibility of configuration format and API</li></ul><p>Breaking changes will be clearly marked in the changelog.</p><hr><p><strong>Last Updated</strong>: 2026-01-27</p>',80)])])}const m=o(a,[["render",r]]);export{h as __pageData,m as default};
